PRICES = {
    "haiku":  (1.00, 5.00),
    "sonnet": (3.00, 15.00),
    "opus":   (5.00, 25.00),
}
QUALITY_RANK = {"haiku": 0, "sonnet": 1, "opus": 2}

USAGE = {
    "messages_per_day": 20,
    "avg_input_tokens": 500,
    "avg_output_tokens": 200,
}

def monthly_cost(model):
    in_rate, out_rate = PRICES[model]
    per_call = (USAGE["avg_input_tokens"]  / 1_000_000) * in_rate \
             + (USAGE["avg_output_tokens"] / 1_000_000) * out_rate
    return per_call * USAGE["messages_per_day"] * 30

def pick_model(constraint):
    floor_rank = QUALITY_RANK[constraint["quality_floor"]]
    budget     = constraint["max_cost_per_month"]
    candidates = [
        m for m in PRICES
        if QUALITY_RANK[m] >= floor_rank and monthly_cost(m) <= budget
    ]
    if not candidates:
        return "none"
    return min(candidates, key=monthly_cost)

scenarios = [
    ("tight budget, haiku floor",   {"max_cost_per_month": 1.00,   "quality_floor": "haiku"}),
    ("mid budget, sonnet floor",    {"max_cost_per_month": 5.00,   "quality_floor": "sonnet"}),
    ("big budget, opus floor",      {"max_cost_per_month": 20.00,  "quality_floor": "opus"}),
    ("tight budget, sonnet floor",  {"max_cost_per_month": 1.00,   "quality_floor": "sonnet"}),
    ("big budget, haiku floor",     {"max_cost_per_month": 100.00, "quality_floor": "haiku"}),
]
for label, c in scenarios:
    print(f"{label + ':':28s} {pick_model(c)}")
